MATCH (m:Movie)
WHERE EXISTS {
    MATCH (m)-[:releasedIn]->(c:Country)
    WHERE c.name = 'France'
}
OR EXISTS {
    MATCH (m)-[r:receivesAward]->(a:Award)
    WHERE a.name = 'Independent Spirit Award' AND 'Best Male Lead' IN r.winners
}
RETURN count(m) AS numberOfMovies

MATCH (m:Movie)
WHERE EXISTS {
  MATCH (m)-[:partOfSeries]->(fs:FilmSeries)
  WHERE fs.name = 'EON James Bond'
}
OR EXISTS {
  MATCH (m)-[:directedBy]->(p:Person)
  WHERE p.name = 'Roger Spottiswoode'
}
RETURN count(m)

